import React, { useState } from "react";
import { getSongsByMood } from "./api";
import axios from "axios";

function App() {
  const [songs, setSongs] = useState([]);
  const [favorites, setFavorites] = useState([]);

  const BASE_URL = "http://127.0.0.1:5000";

  // 🎧 MOOD SONGS
  const fetchSongs = async (mood) => {
    const res = await getSongsByMood(mood);
    setSongs(res.data);
  };

  // 🔍 SEARCH
  const searchSongs = async (text) => {
    if (!text) return;
    const res = await axios.get(`${BASE_URL}/search/${text}`);
    setSongs(res.data);
  };

  // ❤️ FAVORITES
  const toggleFavorite = (title) => {
    if (favorites.includes(title)) {
      setFavorites(favorites.filter((s) => s !== title));
    } else {
      setFavorites([...favorites, title]);
    }
  };

  return (
    <div
      style={{
        textAlign: "center",
        minHeight: "100vh",
        padding: "20px",
        background: "linear-gradient(to right, #0f2027, #203a43, #2c5364)",
        color: "white"
      }}
    >
      <h1>🎧 Mood Music App</h1>

      {/* SEARCH */}
      <input
        type="text"
        placeholder="🔍 Search songs..."
        onChange={(e) => searchSongs(e.target.value)}
        style={{
          padding: "10px",
          width: "250px",
          borderRadius: "10px",
          border: "none",
          marginBottom: "20px"
        }}
      />

      {/* MOOD BUTTONS */}
      <div>
        <button onClick={() => fetchSongs("happy")}>Happy 😊</button>
        <button onClick={() => fetchSongs("sad")}>Sad 😢</button>
        <button onClick={() => fetchSongs("love")}>Love ❤️</button>
        <button onClick={() => fetchSongs("relax")}>Relax 😌</button>
      </div>

      {/* SONG LIST */}
      <h2>🎶 Songs</h2>

      {songs.length === 0 ? (
        <p>No songs found</p>
      ) : (
        songs.map((song, i) => (
          <div
            key={i}
            style={{
              background: "rgba(255,255,255,0.1)",
              margin: "10px auto",
              padding: "15px",
              width: "350px",
              borderRadius: "12px"
            }}
          >
            <h3>{song.title}</h3>
            <p>{song.artist}</p>

            {/* 🎧 PLAYER */}
            {song.url && (
              <audio controls style={{ width: "100%" }}>
                <source src={song.url} type="audio/mp3" />
              </audio>
            )}

            {/* ❤️ FAVORITE */}
            <button
              onClick={() => toggleFavorite(song.title)}
              style={{
                background: "transparent",
                border: "none",
                fontSize: "18px",
                cursor: "pointer",
                color: favorites.includes(song.title) ? "red" : "white"
              }}
            >
              ❤️
            </button>
          </div>
        ))
      )}

      {/* FAVORITES */}
      <h2>❤️ Favorites</h2>

      {favorites.map((song, i) => (
        <p key={i}>⭐ {song}</p>
      ))}
    </div>
  );
}

export default App;
